mapper.update:
UPDATE failure_deal
severity_level = #{severityLevel}, process_time = #{processTime}, process_description = #{processDescription}, updated_at = #{updatedAt},
WHERE failure_id = #{failureId}

mapper.select:
SELECT f.id, f.failure_code AS failureCode, f.device_part_code AS devicePartCode, f.device_part_name AS devicePartName, f.failure_name AS failureName, f.failure_phenomenon AS failurePhenomenon, f.failure_description AS failureDescription, f.failure_notice_type AS failureNoticeType, f.failure_type AS failureType, f.failure_start_time AS failureStartTime, f.status, f.creator_username AS creatorUsername, f.creator_name AS creatorName, f.created_at AS createdAt, f.updated_at AS updatedAt, d.severity_level AS severityLevel, d.process_time AS processTime, d.process_description AS processDescription FROM failure_record f LEFT JOIN failure_deal d ON d.failure_id = f.id
AND f.creator_username = #{creatorUsername}
AND f.failure_code LIKE CONCAT('%', #{failureCode}, '%')
AND f.device_part_code LIKE CONCAT('%', #{devicePartCode}, '%')
AND f.failure_name LIKE CONCAT('%', #{failureName}, '%')
AND DATE(f.failure_start_time) = #{failureStartTime}
AND f.status = #{status}
AND f.failure_type = #{failureType}
ORDER BY f.id DESC

SELECT f.id, f.failure_code AS failureCode, f.device_part_code AS devicePartCode, f.device_part_name AS devicePartName, f.failure_name AS failureName, f.failure_phenomenon AS failurePhenomenon, f.failure_description AS failureDescription, f.failure_notice_type AS failureNoticeType, f.failure_type AS failureType, f.failure_start_time AS failureStartTime, f.status, f.creator_username AS creatorUsername, f.creator_name AS creatorName, f.created_at AS createdAt, f.updated_at AS updatedAt, d.severity_level AS severityLevel, d.process_time AS processTime, d.process_description AS processDescription FROM failure_record f LEFT JOIN failure_deal d ON d.failure_id = f.id
AND f.status IN ('02', '03')
AND f.creator_username = #{creatorUsername}
AND f.failure_code LIKE CONCAT('%', #{failureCode}, '%')
AND f.device_part_code LIKE CONCAT('%', #{devicePartCode}, '%')
AND f.failure_name LIKE CONCAT('%', #{failureName}, '%')
AND DATE(f.failure_start_time) = #{failureStartTime}
AND f.status = #{status}
AND f.failure_type = #{failureType}
ORDER BY f.id DESC
